// Web search tool – uses DuckDuckGo Instant Answer API (no key required).
[Description("Search the web for a topic and return a summary of the top results. Use short, focused queries.")]
static async Task<string> SearchWeb(
    [Description("The search query")] string query,
    HttpClient httpClient)
{
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        var response = await httpClient.GetFromJsonAsync<JsonElement>(url);

        var results = new List<string>();

        var abstractText = response.GetProperty("AbstractText").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            var source = response.GetProperty("AbstractSource").GetString();
            results.Add($"[{source}] {abstractText}");
        }

        if (response.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(5))
            {
                if (topic.TryGetProperty("Text", out var text) &&
                    !string.IsNullOrWhiteSpace(text.GetString()))
                {
                    var firstUrl = topic.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : "";
                    results.Add($"- {text.GetString()} ({firstUrl})");
                }
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found. Try rephrasing the query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

// Note-taking tool – accumulates findings across agent turns.
[Description("Save a research note. Use this to record key findings, facts, or quotes discovered during research.")]
static string SaveNote(
    [Description("A concise title for this note")] string title,
    [Description("The content of the note")] string content,
    ResearchNotebook notebook)
{
    notebook.Add(title, content);
    return $"Note saved: \"{title}\" (total notes: {notebook.Count})";
}

[Description("Retrieve all saved research notes.")]
static string GetNotes(ResearchNotebook notebook)
{
    return notebook.Count == 0
        ? "No notes saved yet."
        : notebook.ToString();
}

// --- Build the agent ---------------------------------------------------------

IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWeb, new AIFunctionFactoryOptions { Services = [KeyValuePair.Create(typeof(HttpClient), (object?)httpClient)] }),
    AIFunctionFactory.Create(SaveNote, new AIFunctionFactoryOptions { Services = [KeyValuePair.Create(typeof(ResearchNotebook), (object?)notebook)] }),
    AIFunctionFactory.Create(GetNotes, new AIFunctionFactoryOptions { Services = [KeyValuePair.Create(typeof(ResearchNotebook), (object?)notebook)] }),
};

