static async Task<string> SearchWebAsync(string query, HttpClient httpClient)
{
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        var response = await httpClient.GetFromJsonAsync<JsonElement>(url);

        var results = new List<string>();

        var abstractText = response.GetProperty("AbstractText").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            var source = response.GetProperty("AbstractSource").GetString();
            results.Add($"[{source}] {abstractText}");
        }

        if (response.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(5))
            {
                if (topic.TryGetProperty("Text", out var text) &&
                    !string.IsNullOrWhiteSpace(text.GetString()))
                {
                    var firstUrl = topic.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : "";
                    results.Add($"- {text.GetString()} ({firstUrl})");
                }
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found. Try rephrasing the query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

