 using System.ComponentModel;
 using System.Net.Http.Json;
 using System.Text.Json;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

 // --- Tool implementations ---------------------------------------------------

 var notebook = new ResearchNotebook();
 using var httpClient = new HttpClient();

 static async Task<string> SearchWebAsync(string query, HttpClient httpClient)
 {
     try
     {
         var encoded = Uri.EscapeDataString(query);
         var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

         var response = await httpClient.GetFromJsonAsync<JsonElement>(url);

         var results = new List<string>();

         var abstractText = response.GetProperty("AbstractText").GetString();
         if (!string.IsNullOrWhiteSpace(abstractText))
         {
             var source = response.GetProperty("AbstractSource").GetString();
             results.Add($"[{source}] {abstractText}");
         }

         if (response.TryGetProperty("RelatedTopics", out var topics))
         {
             foreach (var topic in topics.EnumerateArray().Take(5))
             {
                 if (topic.TryGetProperty("Text", out var text) &&
                     !string.IsNullOrWhiteSpace(text.GetString()))
                 {
                     var firstUrl = topic.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : "";
                     results.Add($"- {text.GetString()} ({firstUrl})");
                 }
             }
         }

         return results.Count > 0
             ? string.Join("\n\n", results)
             : "No results found. Try rephrasing the query.";
     }
     catch (Exception ex)
     {
         return $"Search failed: {ex.Message}";
     }
 }

 // --- Build the agent ---------------------------------------------------------

 IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(
         ([Description("The search query")] string query) => SearchWebAsync(query, httpClient),
         "SearchWeb",
         "Search the web for a topic and return a summary of the top results. Use short, focused queries."),

     AIFunctionFactory.Create(
         ([Description("A concise title for this note")] string title,
          [Description("The content of the note")] string content) =>
         {
             notebook.Add(title, content);
             return $"Note saved: \"{title}\" (total notes: {notebook.Count})";
         },
         "SaveNote",
         "Save a research note. Use this to record key findings, facts, or quotes discovered during research."),

     AIFunctionFactory.Create(
         () => notebook.Count == 0 ? "No notes saved yet." : notebook.ToString(),
         "GetNotes",
         "Retrieve all saved research notes."),
 };

 var agent = new ChatClientAgent(
     chatClient,
     new ChatClientAgentOptions
     {
         Name = "ResearchAgent",
         Description = "An AI research assistant that searches the web and takes notes.",
         ChatOptions = new ChatOptions
         {
             Temperature = 0f,
             MaxOutputTokens = 2048,
             Tools = [.. tools],
         },
     });

 // --- Run the agent -----------------------------------------------------------

 Console.WriteLine("╔══════════════════════════════════════════╗");
 Console.WriteLine("║        AI Research Agent (MAF)           ║");
 Console.WriteLine("╠══════════════════════════════════════════╣");
 Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
 Console.WriteLine("╚══════════════════════════════════════════╝");
 Console.WriteLine();

 while (true)
 {
     Console.ForegroundColor = ConsoleColor.Cyan;
     Console.Write("Research topic> ");
     Console.ResetColor();

     var topic = Console.ReadLine()?.Trim();
     if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
     {
         break;
     }

     notebook.Clear();

     var instructions = $"""
         You are a thorough research assistant. Your goal is to research the topic below
         by searching the web multiple times with different queries, saving important
         findings as notes, then producing a well-structured summary.

         Follow these steps:
         1. Search the web 2-3 times with varied queries to gather broad information.
         2. Save the most important findings as notes using the SaveNote tool.
         3. Review your notes with GetNotes.
         4. Produce a final summary with sections: Overview, Key Findings, and Sources.

         Topic: {topic}
         """;

     Console.WriteLine();
     Console.ForegroundColor = ConsoleColor.DarkGray;
     Console.WriteLine("Researching... (the agent will search & take notes autonomously)");
     Console.ResetColor();
     Console.WriteLine();

     try
     {
         var session = await agent.CreateSessionAsync();

         var response = await agent.RunAsync(instructions, session, new ChatClientAgentRunOptions(
             new ChatOptions
             {
                 Temperature = 0f,
                 MaxOutputTokens = 2048,
             }));

         Console.ForegroundColor = ConsoleColor.Green;
         Console.WriteLine("═══ Research Summary ═══");
         Console.ResetColor();
         Console.WriteLine(response.Text);
         Console.WriteLine();
     }
     catch (Exception ex)
     {
         Console.ForegroundColor = ConsoleColor.Red;
         Console.WriteLine($"Error: {ex.Message}");
         Console.ResetColor();
     }
 }

 Console.WriteLine("Goodbye!");

 // --- Supporting types --------------------------------------------------------

 sealed class ResearchNotebook
 {
     private readonly List<(string Title, string Content)> _notes = [];

     public int Count => _notes.Count;

     public void Add(string title, string content) => _notes.Add((title, content));

     public void Clear() => _notes.Clear();

     public override string ToString()
     {
         var sb = new System.Text.StringBuilder();
         for (var i = 0; i < _notes.Count; i++)
         {
             sb.AppendLine($"## Note {i + 1}: {_notes[i].Title}");
             sb.AppendLine(_notes[i].Content);
             sb.AppendLine();
         }
         return sb.ToString();
     }
 }

